import{_ as r,o as t,c as a,ag as o}from"./chunks/framework.DGzMGr_a.js";const b=JSON.parse('{"title":"React 的协调（Reconciliation）和 Fiber 架构解决了什么问题？","description":"","frontmatter":{"title":"React 的协调（Reconciliation）和 Fiber 架构解决了什么问题？","difficulty":"hard","tags":["Reconciliation","Fiber","虚拟DOM","调度"],"estimate":30},"headers":[],"relativePath":"domains/react/qa/09-reconciliation-fiber.md","filePath":"domains/react/qa/09-reconciliation-fiber.md","lastUpdated":1783504823000}'),n={name:"domains/react/qa/09-reconciliation-fiber.md"};function i(c,e,s,l,d,g){return t(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="问答题-09-高级-react-的协调-reconciliation-和-fiber-架构解决了什么问题" tabindex="-1">问答题 09（高级）：React 的协调（Reconciliation）和 Fiber 架构解决了什么问题？ <a class="header-anchor" href="#问答题-09-高级-react-的协调-reconciliation-和-fiber-架构解决了什么问题" aria-label="Permalink to &quot;问答题 09（高级）：React 的协调（Reconciliation）和 Fiber 架构解决了什么问题？&quot;">​</a></h1><h2 id="参考答案" tabindex="-1">参考答案 <a class="header-anchor" href="#参考答案" aria-label="Permalink to &quot;参考答案&quot;">​</a></h2><p><strong>Reconciliation（协调）</strong> 是 React 比较新旧虚拟 DOM 树、决定如何以最小代价更新真实 DOM 的过程。核心启发式规则：</p><ol><li><strong>不同类型的元素直接销毁重建</strong>（<code>&lt;div&gt;</code> → <code>&lt;span&gt;</code> 不复用）。</li><li><strong>同类型元素比较 props</strong>，只更新变化的属性。</li><li><strong>列表按 key 匹配</strong>，key 相同则复用组件实例。</li></ol><p><strong>Fiber 架构</strong>（React 16+）把原本递归、不可中断的协调过程改造成<strong>基于链表的可中断单元任务调度</strong>：</p><ul><li>每个 Fiber 节点代表一个工作单元，形成 child/sibling/return 三向链表；</li><li>渲染分为 <strong>render 阶段</strong>（可中断、可复用、可丢弃，只做 diff 计算）和 <strong>commit 阶段</strong>（同步、不可中断，真正更新 DOM）；</li><li>结合 <strong>Scheduler</strong> 按优先级（Lane）分片处理，将大量渲染拆到多个&quot;时间片&quot;里，避免长任务阻塞主线程，为 Concurrent Features（Suspense、useTransition、并发渲染）打下基础。</li></ul><p>一句话：Reconciliation 决定&quot;改什么&quot;，Fiber 决定&quot;怎么以可中断、可优先级化的方式改&quot;。</p><h2 id="追问" tabindex="-1">追问 <a class="header-anchor" href="#追问" aria-label="Permalink to &quot;追问&quot;">​</a></h2><h3 id="追问-1-什么是-双缓冲-为什么-fiber-需要-workinprogress-树" tabindex="-1">追问 1：什么是&quot;双缓冲&quot;？为什么 Fiber 需要 workInProgress 树？ <a class="header-anchor" href="#追问-1-什么是-双缓冲-为什么-fiber-需要-workinprogress-树" aria-label="Permalink to &quot;追问 1：什么是&quot;双缓冲&quot;？为什么 Fiber 需要 workInProgress 树？&quot;">​</a></h3><p><strong>参考答案</strong>：React 内部同时维护 <code>current</code>（已提交到屏幕的树）和 <code>workInProgress</code>（正在构建的树）两棵 Fiber。所有更新在 workInProgress 上进行，可随时丢弃或重来；构建完成后一次性替换 current。这种&quot;离屏构建、原子提交&quot;的模式称为<strong>双缓冲</strong>，避免了半成品状态被用户看到，也让 render 阶段可中断。</p><h3 id="追问-2-fiber-中不同优先级-lane-如何影响更新" tabindex="-1">追问 2：Fiber 中不同优先级（Lane）如何影响更新？ <a class="header-anchor" href="#追问-2-fiber-中不同优先级-lane-如何影响更新" aria-label="Permalink to &quot;追问 2：Fiber 中不同优先级（Lane）如何影响更新？&quot;">​</a></h3><p><strong>参考答案</strong>：React 18 用 <strong>Lane 模型</strong>（一组 31 位 bit flag）标记更新的紧急程度。用户输入等交互更新走 SyncLane / InputContinuousLane（高优先级），<code>useTransition</code> 中的过渡更新走 TransitionLane（低优先级）。调度器优先处理高优 Lane，低优任务可被打断、被更高优抢占，从而在保持响应性的同时把慢更新推迟。</p><h3 id="追问-3-并发渲染-concurrent-rendering-会带来什么坑" tabindex="-1">追问 3：并发渲染（Concurrent Rendering）会带来什么坑？ <a class="header-anchor" href="#追问-3-并发渲染-concurrent-rendering-会带来什么坑" aria-label="Permalink to &quot;追问 3：并发渲染（Concurrent Rendering）会带来什么坑？&quot;">​</a></h3><p><strong>参考答案</strong>：因为 render 阶段可中断、可能被丢弃再重跑，<strong>渲染函数必须是纯函数</strong>，副作用只能放进 effect。若在渲染中直接读写外部变量、发起请求或修改 ref，可能被执行多次导致状态不一致；useEffect 在 StrictMode + 开发环境会有意&quot;挂载—卸载—再挂载&quot;以暴露此类错误。</p><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><blockquote><p>深入阅读请从标注 <strong>首选</strong> 的来源开始；本领域完整索引见 <a href="/domains/react/RESOURCES">React 参考资料</a>。</p></blockquote><ul><li><strong>首选</strong> — <a href="https://react.dev/learn/render-and-commit" target="_blank" rel="noreferrer">React: Render and Commit</a>：render 与 commit 两阶段及 Fiber 工作单元</li><li><a href="https://react.dev/blog/2022/03/29/react-v18" target="_blank" rel="noreferrer">React 18 Blog</a>：并发渲染与可中断协调的设计背景</li><li><a href="https://github.com/facebook/react/tree/main/packages/react-reconciler" target="_blank" rel="noreferrer">react-reconciler 源码</a>：双缓冲与 Lane 调度的实现入口</li></ul>',17)])])}const h=r(n,[["render",i]]);export{b as __pageData,h as default};
